import React, { useContext } from 'react';
import { BrowserRouter, Routes, Route, Link } from 'react-router-dom';
import { AppProvider, AppContext } from './context/AppContext';

// Импорт страниц (убедись, что пути верные)
import CatalogPage from './pages/CatalogPage';
import LoginPage from './pages/LoginPage';
import ProfilePage from './pages/ProfilePage';
import AdminPage from './pages/AdminPage';

// Компонент шапки сайта
const Header = () => {
  const { user, setUser } = useContext(AppContext);

  return (
    <nav style={{ 
      background: '#1a1a1a', 
      padding: '15px 5%', 
      display: 'flex', 
      justifyContent: 'space-between', 
      alignItems: 'center',
      color: 'white' 
    }}>
      <Link to="/" style={{ color: 'white', fontSize: '1.5rem', fontWeight: 'bold', textDecoration: 'none' }}>
        SNEAKER SHOP
      </Link>
      
      <div style={{ display: 'flex', gap: '20px', alignItems: 'center' }}>
        <Link to="/" style={{ color: 'white', textDecoration: 'none' }}>Каталог</Link>
        
        {user ? (
          <>
            <Link to="/profile" style={{ color: 'white', textDecoration: 'none' }}>Мои заказы</Link>
            
            {/* Если роль админ — показываем ссылку на админку */}
            {user.role === 'admin' && (
              <Link to="/admin" style={{ color: '#ffcc00', fontWeight: 'bold', textDecoration: 'none' }}>
                Админ-панель
              </Link>
            )}
            
            <button 
              onClick={() => setUser(null)} 
              style={{ background: '#444', border: 'none', color: 'white', padding: '5px 10px', cursor: 'pointer', borderRadius: '5px' }}
            >
              Выйти ({user.username})
            </button>
          </>
        ) : (
          <Link to="/login" style={{ color: 'white', textDecoration: 'none' }}>Вход</Link>
        )}
      </div>
    </nav>
  );
};

function App() {
  return (
    <AppProvider>
      <BrowserRouter>
        <div className="App">
          <Header />
          <Routes>
            <Route path="/" element={<CatalogPage />} />
            <Route path="/login" element={<LoginPage />} />
            <Route path="/profile" element={<ProfilePage />} />
            <Route path="/admin" element={<AdminPage />} />
          </Routes>
        </div>
      </BrowserRouter>
    </AppProvider>
  );
}

export default App;
